// LESSON: Map Overview - Reference Page 2.
// You will learn: Use key lookup, map views, computeIfAbsent, merge, and TreeMap ranges.
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.TreeMap;

class MapOverviewReference {
  public static void main(String[] args) {
    example1BasicOperations();
    example2ViewsAndEntries();
    example3ComputedUpdates();
    example4SortedTreeMap();
  }

  static void example1BasicOperations() {
    Map<String, Integer> ages = new HashMap<>();
    ages.put("Ada", 17);
    ages.put("Bo", 18);
    int adaAge = ages.get("Ada");
    int missingAge = ages.getOrDefault("Cy", 0);
    boolean hasBo = ages.containsKey("Bo");
    ages.remove("Bo");
    System.out.println(adaAge + " " + missingAge + " " + hasBo);
  }

  static void example2ViewsAndEntries() {
    Map<String, String> capitals = new HashMap<>();
    capitals.put("Sweden", "Stockholm");
    capitals.put("Norway", "Oslo");
    for (String country : capitals.keySet()) {
      System.out.println(country);
    }
    System.out.println(capitals.values());
    for (Map.Entry<String, String> entry : capitals.entrySet()) {
      System.out.println(entry.getKey() + " -> " + entry.getValue());
    }
  }

  static void example3ComputedUpdates() {
    Map<String, List<String>> groups = new HashMap<>();
    groups.computeIfAbsent("Prog2", key -> new ArrayList<String>()).add("Mina");
    groups.computeIfAbsent("Prog2", key -> new ArrayList<String>()).add("Leo");
    Map<String, Integer> counts = new HashMap<>();
    counts.merge("java", 1, (oldCount, added) -> oldCount + added);
    counts.merge("java", 1, (oldCount, added) -> oldCount + added);
    System.out.println(groups + " " + counts);
  }

  static void example4SortedTreeMap() {
    TreeMap<Integer, String> rooms = new TreeMap<>();
    rooms.put(101, "Lab");
    rooms.put(203, "Classroom");
    rooms.put(150, "Office");
    System.out.println(rooms.firstKey());
    System.out.println(rooms.lastKey());
    System.out.println(rooms.headMap(200));
    System.out.println(rooms.tailMap(150));
    System.out.println(rooms.subMap(100, 204));
  }
}
